CustomField.formula:
IF( AND(NOT( ISNULL(PoC_Details_Provided_Date__c) ), NOT( ISNULL(No_PoC_Required_Date__c) ) 
), 
IF(PoC_Details_Provided_Date__c > No_PoC_Required_Date__c, PoC_Details_Provided_By__c, 
No_PoC_Required_Set_By__c
), 
IF(ISNULL(PoC_Details_Provided_Date__c), No_PoC_Required_Set_By__c, 
IF(ISNULL(No_PoC_Required_Date__c), PoC_Details_Provided_By__c,null) 
) 
)
